// Extract and normalize file metadata from Google Drive Trigger
const triggerData = $input.item.json;

const fileId = triggerData.id || triggerData.fileId || '';
const fileName = triggerData.name || triggerData.title || 'unknown';
const mimeType = triggerData.mimeType || triggerData.mime_type || '';
const fileSize = triggerData.size || triggerData.fileSize || 0;
const createdTime = triggerData.createdTime || triggerData.createdDate || new Date().toISOString();

return {
  json: {
    fileId,
    fileName,
    mimeType,
    fileSize: parseInt(fileSize, 10) || 0,
    createdTime,
    originalData: triggerData
  }
};

