// Prepare data for Supabase insert into dedup_audit_log
return {
  json: {
    file_id: $('Prepare File Info').item.json.fileId,
    file_name: $('Prepare File Info').item.json.fileName,
    hash: $('Crypto').item.json.hash,
    status: 'duplicate',
    action_taken: 'moved_to_duplicates'
  }
};

// Prepare data for Supabase insert into file_hashes
return {
  json: {
    file_id: $('Prepare File Info').item.json.fileId,
    file_name: $('Prepare File Info').item.json.fileName,
    hash: $('Crypto').item.json.hash,
    file_size: $('Prepare File Info').item.json.fileSize,
    mime_type: $('Prepare File Info').item.json.mimeType
  }
};

// Check if the insert was successful or if a conflict/error occurred
const item = $input.item.json;

if (item.error) {
  return {
    json: {
      status: 'duplicate_race_condition',
      message: 'Concurrent upload detected - hash already exists',
      error: item.error
    }
  };
}

// If the response doesn't contain an id, it may be a conflict
if (!item.id && item.id !== 0) {
  return {
    json: {
      status: 'duplicate_race_condition',
      message: 'Hash already existed (conflict detected)',
      fileId: $('Prepare File Info').item.json.fileId,
      fileName: $('Prepare File Info').item.json.fileName
    }
  };
}

return {
  json: {
    status: 'unique_inserted',
    insertedId: item.id,
    fileId: $('Prepare File Info').item.json.fileId,
    fileName: $('Prepare File Info').item.json.fileName
  }
};

// Prepare data for Supabase insert into dedup_audit_log
const status = $json.status;
return {
  json: {
    file_id: $('Prepare File Info').item.json.fileId,
    file_name: $('Prepare File Info').item.json.fileName,
    hash: $('Crypto').item.json.hash,
    status: status,
    action_taken: status === 'unique_inserted' ? 'stored_hash' : 'race_condition_caught'
  }
};

const fileInfo = $('Prepare File Info').item.json;

return {
  json: {
    status: 'error',
    errorType: 'missing_binary',
    message: `Binary data missing for file: ${fileInfo.fileName} (${fileInfo.fileId})`,
    fileId: fileInfo.fileId,
    fileName: fileInfo.fileName,
    mimeType: fileInfo.mimeType,
    timestamp: new Date().toISOString()
  }
};

// Prepare data for Supabase insert into dedup_audit_log
return {
  json: {
    file_id: $json.fileId,
    file_name: $json.fileName,
    hash: null,
    status: 'error',
    action_taken: 'none',
    error_message: $json.message
  }
};
